fn fibonacci(n: Number) -> [Number] {
    if n <= 0 { return [] }
    if n == 1 { return [0] }
    if n == 2 { return [0, 1] }
    results = [0, 1]
    for i in range(2, n) {
        next = get(results, i - 1) + get(results, i - 2)
        results = append(results, next)
    }
    return results
}
entry main(x: Text) { return fibonacci(10) }

