pure fn mean(numbers: [Number]) -> Number {
    total = 0
    for n in numbers { total = total + n }
    return total / length(numbers)
}
pure fn variance(numbers: [Number]) -> Number {
    avg = mean(numbers)
    total = 0
    for n in numbers { total = total + pow(n - avg, 2) }
    return total / length(numbers)
}
pure fn stdev(numbers: [Number]) -> Number {
    return sqrt(variance(numbers))
}
entry main(x: Text) {
    numbers = [10, 12, 23, 23, 16, 23, 21, 16]
    std_dev = stdev(numbers)
    if std_dev > 5 { return join([to_text(std_dev), " — highly variable"], "") }
    return join([to_text(std_dev), " — not highly variable"], "")
}

