import re
from urllib.parse import urlencode
import urllib.request
import json

def validate_email(email):
    return re.match(r"[^@]+@[^@]+\.[^@]+", email) is not None

def draft_greeting(name, email):
    return f"Hello {name}, welcome to our service. Please contact {email} for any questions."

def main():
    text = "Contact alice@test.com or bob@test.com for info"
    emails = re.findall(r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b', text)
    greetings = []
    for email in emails:
        if validate_email(email):
            name = email.split('@')[0]
            greetings.append(draft_greeting(name, email))
    return '\n'.join(greetings)

print(main())

